     1→import { Logger } from '@nestjs/common';
     2→import { plainToInstance } from 'class-transformer';
     3→import {
     4→	IsBoolean,
     5→	IsEnum,
     6→	IsNotEmpty,
     7→	IsNumber,
     8→	IsString,
     9→	Max,
    10→	Min,
    11→	validateSync,
    12→} from 'class-validator';
    13→
    14→import { Environment } from '@interfaces/env-variables.interface';
    15→
    16→class EnvironmentVariables {
    17→	@IsEnum(Environment)
    18→	NODE_ENV: Environment;
    19→
    20→	@IsNumber()
    21→	@Min(0)
    22→	@Max(65535)
    23→	PORT: number;
    24→
    25→	@IsString()
    26→	@IsNotEmpty()
    27→	GLOBAL_PREFIX: string;
    28→
    29→	@IsString()
    30→	@IsNotEmpty()
    31→	SERVER_NAME: string;
    32→
    33→	@IsBoolean()
    34→	IS_COMPACT_LOGS: boolean;
    35→
    36→	@IsBoolean()
    37→	IS_JSON_LIKE_LOGS: boolean;
    38→
    39→	@IsNumber()
    40→	@Min(0)
    41→	@Max(60000)
    42→	GRACEFUL_SHUTDOWN_DELAY: number;
    43→}
    44→
    45→export function validate({
    46→	envConfig,
    47→}: {
    48→	envConfig: Record<string, unknown>;
    49→}): EnvironmentVariables {
    50→	const validatedConfig = plainToInstance(EnvironmentVariables, envConfig, {
    51→		enableImplicitConversion: true,
    52→	});
    53→
    54→	const errors = validateSync(validatedConfig, {
    55→		skipMissingProperties: false,
    56→		forbidUnknownValues: true,
    57→		stopAtFirstError: true,
    58→		forbidNonWhitelisted: true,
    59→	});
    60→
    61→	if (errors.length > 0) {
    62→		Logger.error('Config validation error', errors);
    63→		throw new Error(errors.toString());
    64→	}
    65→
    66→	return validatedConfig;
    67→}
