     1→import { Logger, ValidationPipe } from '@nestjs/common';
     2→import { NestFactory } from '@nestjs/core';
     3→import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
     4→
     5→import { AppModule } from '@modules/app/app.module';
     6→
     7→import { getEnv } from '@utils/get-env-variable.util';
     8→import { setupSwagger } from '@utils/setup-swagger.util';
     9→
    10→import { GLOBAL_PREFIX, NODE_ENV, PORT } from '@constants/env-variables.constant';
    11→
    12→import { Environment } from '@interfaces/env-variables.interface';
    13→
    14→declare const module: {
    15→	hot?: { accept: () => void; dispose: (callback: () => void) => void };
    16→};
    17→
    18→async function bootstrap(): Promise<NestFastifyApplication> {
    19→	const port = getEnv<number>({ key: PORT, converter: Number });
    20→	const globalPrefix = getEnv<string>({ key: GLOBAL_PREFIX });
    21→	const nodeEnv = getEnv<Environment>({ key: NODE_ENV });
    22→	const isDev = nodeEnv === Environment.DEVELOPMENT;
    23→
    24→	const fastifyAdapter = new FastifyAdapter({ trustProxy: true });
    25→
    26→	const app = await NestFactory.create<NestFastifyApplication>(
    27→		AppModule,
    28→		fastifyAdapter,
    29→		{
    30→			logger: isDev
    31→				? ['log', 'error', 'warn', 'fatal', 'debug', 'verbose']
    32→				: ['log', 'error', 'warn', 'fatal'],
    33→		},
    34→	);
    35→
    36→	app.enableCors({ origin: true, credentials: true });
    37→
    38→	app.useGlobalPipes(
    39→		new ValidationPipe({ transform: true, whitelist: true, forbidNonWhitelisted: true }),
    40→	);
    41→
    42→	app.setGlobalPrefix(globalPrefix, {
    43→		exclude: ['liveness', 'readiness'],
    44→	});
    45→
    46→	setupSwagger({ app, fastifyAdapter, globalPrefix });
    47→
    48→	if (!isDev) {
    49→		app.enableShutdownHooks();
    50→	}
    51→
    52→	await app.listen(port, '0.0.0.0');
    53→
    54→	Logger.log(`Application running on port ${String(port)}`, 'Bootstrap');
    55→
    56→	return app;
    57→}
    58→
    59→let app: NestFastifyApplication | undefined;
    60→
    61→async function startApp(): Promise<void> {
    62→	try {
    63→		app = await bootstrap();
    64→	} catch (err: unknown) {
    65→		Logger.error('Failed to start application', err, 'Bootstrap');
    66→		process.exit(1);
    67→	}
    68→}
    69→
    70→void startApp();
    71→
    72→if (module.hot) {
    73→	module.hot.accept();
    74→	module.hot.dispose(() => {
    75→		void app?.close();
    76→	});
    77→}
    78→

