import * as fs from 'node:fs';
import * as path from 'node:path';

import { ConfigFactory } from '@nestjs/config';
import * as dotenv from 'dotenv';

import { validate } from '@config/env-validations.config';

import { isDevEnv, isProdEnv, isStagingEnv, isTestEnv } from '@utils/common.util';

export const getEnvFile = (): string => {
	if (isTestEnv()) return '.env.test';
	return '.env';
};

export const getEnvVariables = (): Record<string, string | number | undefined> => ({
	NODE_ENV: process.env['NODE_ENV'],
	PORT: process.env['PORT'],
	GLOBAL_PREFIX: process.env['GLOBAL_PREFIX'],
	SERVER_NAME: process.env['SERVER_NAME'],
	IS_COMPACT_LOGS: process.env['IS_COMPACT_LOGS'],
	IS_JSON_LIKE_LOGS: process.env['IS_JSON_LIKE_LOGS'],
	GRACEFUL_SHUTDOWN_DELAY: process.env['GRACEFUL_SHUTDOWN_DELAY'],
});

export const loadEnvVariables = (): ConfigFactory[] => {
	if (isStagingEnv() || isProdEnv()) {
		validate({ envConfig: getEnvVariables() });
		return [getEnvVariables];
	}

	const envFilePath = path.resolve(process.cwd(), getEnvFile());

	if (!fs.existsSync(envFilePath)) {
		if (isDevEnv()) {
			throw new Error(`Env file not found: ${envFilePath}`);
		}
		return [() => ({})];
	}

	const envConfig = dotenv.parse(fs.readFileSync(envFilePath));

	validate({ envConfig });

	return [() => envConfig];
};

