import { Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { Test, TestingModule } from '@nestjs/testing';

import { EnvConfigService } from '@modules/env-config/env-config.service';

describe('EnvConfigService', () => {
	let service: EnvConfigService;
	let configServiceGetMock: jest.Mock;
	let loggerSpy: jest.SpyInstance;

	beforeEach(async () => {
		configServiceGetMock = jest.fn();

		const module: TestingModule = await Test.createTestingModule({
			providers: [
				EnvConfigService,
				{
					provide: ConfigService,
					useValue: { get: configServiceGetMock },
				},
			],
		}).compile();

		service = module.get<EnvConfigService>(EnvConfigService);
		loggerSpy = jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
	});

	afterEach(() => {
		jest.clearAllMocks();
	});

	it('should be defined', () => {
		expect(service).toBeDefined();
	});

	describe('get', () => {
		it('should return value when env variable is defined', () => {
			configServiceGetMock.mockReturnValue('test-value');

			const result = service.get({ key: 'TEST_KEY' });

			expect(configServiceGetMock).toHaveBeenCalledWith('TEST_KEY');
			expect(loggerSpy).toHaveBeenCalledWith('Fetching env var: TEST_KEY');
			expect(result).toBe('test-value');
		});

		it('should apply converter when provided', () => {
			configServiceGetMock.mockReturnValue('3001');

			const result = service.get({ key: 'PORT', converter: Number });

			expect(result).toBe(3001);
			expect(configServiceGetMock).toHaveBeenCalledWith('PORT');
		});

		it('should throw when env variable is undefined', () => {
			configServiceGetMock.mockReturnValue(undefined);

			expect(() => service.get({ key: 'MISSING_VAR' })).toThrow(
				'Environment variable MISSING_VAR is not defined',
			);
		});
	});
});

