import { Logger } from '@nestjs/common';

import { validate } from '@config/env-validations.config';

const validEnvConfig = {
	NODE_ENV: 'test',
	PORT: '3001',
	GLOBAL_PREFIX: 'api',
	SERVER_NAME: 'webapp-backend-test',
	IS_COMPACT_LOGS: 'true',
	IS_JSON_LIKE_LOGS: 'false',
	GRACEFUL_SHUTDOWN_DELAY: '0',
};

describe('env-validations.config', () => {
	describe('validate', () => {
		let loggerErrorSpy: jest.SpyInstance;

		beforeEach(() => {
			loggerErrorSpy = jest.spyOn(Logger, 'error').mockImplementation(jest.fn());
		});

		afterEach(() => {
			jest.clearAllMocks();
		});

		it('should return validated config for valid input', () => {
			const result = validate({ envConfig: validEnvConfig });

			expect(result).toBeDefined();
			expect(result.NODE_ENV).toBe('test');
			expect(result.PORT).toBe(3001);
			expect(result.GLOBAL_PREFIX).toBe('api');
			expect(result.SERVER_NAME).toBe('webapp-backend-test');
			expect(result.IS_COMPACT_LOGS).toBe(true);
			expect(result.IS_JSON_LIKE_LOGS).toBe(false);
			expect(result.GRACEFUL_SHUTDOWN_DELAY).toBe(0);
		});

		it('should throw when NODE_ENV is invalid enum value', () => {
			expect(() =>
				validate({ envConfig: { ...validEnvConfig, NODE_ENV: 'invalid' } }),
			).toThrow();
			expect(loggerErrorSpy).toHaveBeenCalledWith(
				'Config validation error',
				expect.any(Array),
			);
		});

		it('should throw when PORT is out of range', () => {
			expect(() =>
				validate({ envConfig: { ...validEnvConfig, PORT: '99999' } }),
			).toThrow();
		});

		it('should throw when GRACEFUL_SHUTDOWN_DELAY exceeds max', () => {
			expect(() =>
				validate({ envConfig: { ...validEnvConfig, GRACEFUL_SHUTDOWN_DELAY: '99999' } }),
			).toThrow();
		});

		it('should throw when required string field is empty', () => {
			expect(() =>
				validate({ envConfig: { ...validEnvConfig, GLOBAL_PREFIX: '' } }),
			).toThrow();
		});

		it('should throw when required field is missing', () => {
			const { PORT: _port, ...missingPort } = validEnvConfig;
			expect(() => validate({ envConfig: missingPort })).toThrow();
		});
	});
});

