import * as fs from 'node:fs';

import * as dotenv from 'dotenv';

import { validate } from '@config/env-validations.config';
import { isDevEnv, isProdEnv, isStagingEnv, isTestEnv } from '@utils/common.util';
import { getEnvFile, getEnvVariables, loadEnvVariables } from '@utils/get-env-file.util';

jest.mock('node:fs');
jest.mock('dotenv');
jest.mock('@config/env-validations.config');
jest.mock('@utils/common.util');

const mockIsTestEnv = isTestEnv as jest.MockedFunction<typeof isTestEnv>;
const mockIsProdEnv = isProdEnv as jest.MockedFunction<typeof isProdEnv>;
const mockIsStagingEnv = isStagingEnv as jest.MockedFunction<typeof isStagingEnv>;
const mockIsDevEnv = isDevEnv as jest.MockedFunction<typeof isDevEnv>;
const mockValidate = validate as jest.MockedFunction<typeof validate>;
const mockFsExistsSync = fs.existsSync as jest.MockedFunction<typeof fs.existsSync>;
const mockFsReadFileSync = fs.readFileSync as jest.MockedFunction<typeof fs.readFileSync>;
const mockDotenvParse = dotenv.parse as jest.MockedFunction<typeof dotenv.parse>;

const mockEnvConfig = {
	NODE_ENV: 'test',
	PORT: '3001',
	GLOBAL_PREFIX: 'api',
	SERVER_NAME: 'webapp-backend-test',
	IS_COMPACT_LOGS: 'true',
	IS_JSON_LIKE_LOGS: 'false',
	GRACEFUL_SHUTDOWN_DELAY: '0',
};

describe('get-env-file.util', () => {
	beforeEach(() => {
		jest.clearAllMocks();
		mockIsTestEnv.mockReturnValue(false);
		mockIsProdEnv.mockReturnValue(false);
		mockIsStagingEnv.mockReturnValue(false);
		mockIsDevEnv.mockReturnValue(false);
	});

	describe('getEnvFile', () => {
		it('should return .env.test when in test environment', () => {
			mockIsTestEnv.mockReturnValue(true);
			expect(getEnvFile()).toBe('.env.test');
		});

		it('should return .env when not in test environment', () => {
			mockIsTestEnv.mockReturnValue(false);
			expect(getEnvFile()).toBe('.env');
		});
	});

	describe('getEnvVariables', () => {
		it('should return object with all environment variable keys', () => {
			const originalEnv = process.env;
			process.env = {
				NODE_ENV: 'test',
				PORT: '3001',
				GLOBAL_PREFIX: 'api',
				SERVER_NAME: 'webapp-backend-test',
				IS_COMPACT_LOGS: 'true',
				IS_JSON_LIKE_LOGS: 'false',
				GRACEFUL_SHUTDOWN_DELAY: '0',
			};

			const result = getEnvVariables();

			expect(result).toMatchObject({
				NODE_ENV: 'test',
				PORT: '3001',
				GLOBAL_PREFIX: 'api',
				SERVER_NAME: 'webapp-backend-test',
				IS_COMPACT_LOGS: 'true',
				IS_JSON_LIKE_LOGS: 'false',
				GRACEFUL_SHUTDOWN_DELAY: '0',
			});

			process.env = originalEnv;
		});
	});

	describe('loadEnvVariables', () => {
		it('should validate and return getEnvVariables factory for staging env', () => {
			mockIsStagingEnv.mockReturnValue(true);
			mockValidate.mockReturnValue({} as never);

			const result = loadEnvVariables();

			expect(mockValidate).toHaveBeenCalled();
			expect(result).toHaveLength(1);
			expect(result[0]).toBe(getEnvVariables);
		});

		it('should validate and return getEnvVariables factory for production env', () => {
			mockIsProdEnv.mockReturnValue(true);
			mockValidate.mockReturnValue({} as never);

			const result = loadEnvVariables();

			expect(mockValidate).toHaveBeenCalled();
			expect(result).toHaveLength(1);
			expect(result[0]).toBe(getEnvVariables);
		});

		it('should throw when env file not found in dev environment', () => {
			mockIsDevEnv.mockReturnValue(true);
			mockFsExistsSync.mockReturnValue(false);

			expect(() => loadEnvVariables()).toThrow(/Env file not found/);
		});

		it('should return empty factory when env file not found in non-dev environment', () => {
			mockFsExistsSync.mockReturnValue(false);

			const result = loadEnvVariables();

			expect(result).toHaveLength(1);
			expect(result[0]?.()).toEqual({});
		});

		it('should parse env file, validate, and return config factory when file exists', () => {
			mockFsExistsSync.mockReturnValue(true);
			mockFsReadFileSync.mockReturnValue(Buffer.from(''));
			mockDotenvParse.mockReturnValue(mockEnvConfig);
			mockValidate.mockReturnValue({} as never);

			const result = loadEnvVariables();

			expect(mockDotenvParse).toHaveBeenCalled();
			expect(mockValidate).toHaveBeenCalledWith({ envConfig: mockEnvConfig });
			expect(result).toHaveLength(1);
			expect(result[0]?.()).toEqual(mockEnvConfig);
		});
	});
});

