import { EnvConfigService } from '@modules/env-config/env-config.service';
import { getEnv } from '@utils/get-env-variable.util';

describe('getEnv', () => {
	let getSpy: jest.SpyInstance;

	beforeEach(() => {
		getSpy = jest.spyOn(EnvConfigService.prototype, 'get');
	});

	afterEach(() => {
		jest.restoreAllMocks();
	});

	it('should call EnvConfigService.get without converter', () => {
		getSpy.mockReturnValue('test-value');

