import { HealthCheckResult, HealthCheckService, MemoryHealthIndicator } from '@nestjs/terminus';
import { Test, TestingModule } from '@nestjs/testing';

import { HealthController } from '@modules/health/health.controller';
import { HealthService } from '@modules/health/health.service';

describe('HealthController', () => {
	let controller: HealthController;

	const healthyResult: HealthCheckResult = {
		status: 'ok',
		info: { app: { status: 'up' } },
		error: {},
		details: { app: { status: 'up' } },
	};

	const mockHealth = {
		check: jest.fn().mockResolvedValue(healthyResult),
	};

	const mockMemory = {
		checkHeap: jest.fn().mockResolvedValue({ memory_heap: { status: 'up' } }),
	};

	const mockHealthService = {
		isAppHealthy: jest.fn().mockReturnValue({ app: { status: 'up' } }),
	};

	beforeEach(async () => {
		jest.clearAllMocks();

		const module: TestingModule = await Test.createTestingModule({
			controllers: [HealthController],
			providers: [
				{ provide: HealthCheckService, useValue: mockHealth },
				{ provide: MemoryHealthIndicator, useValue: mockMemory },
				{ provide: HealthService, useValue: mockHealthService },
			],
		}).compile();

		controller = module.get<HealthController>(HealthController);
	});

	it('should be defined', () => {
		expect(controller).toBeDefined();
	});

	describe('isItUp', () => {
		it('should return status up', () => {
			expect(controller.isItUp()).toEqual({ status: 'up' });
		});
	});

	describe('isItWorking', () => {
		it('should call health.check with app and memory indicators', async () => {
			const result = await controller.isItWorking();

			expect(mockHealth.check).toHaveBeenCalledWith([
				expect.any(Function),
				expect.any(Function),
			]);
			expect(result).toEqual(healthyResult);
		});

		it('should call healthService.isAppHealthy via the first check function', async () => {
			await controller.isItWorking();

			const [firstFn] = mockHealth.check.mock.calls[0][0] as (() => unknown)[];
			firstFn?.();

			expect(mockHealthService.isAppHealthy).toHaveBeenCalled();
		});

		it('should call memory.checkHeap via the second check function', async () => {
			await controller.isItWorking();

			const [, secondFn] = mockHealth.check.mock.calls[0][0] as (() => unknown)[];
			secondFn?.();

			expect(mockMemory.checkHeap).toHaveBeenCalledWith(
				'memory_heap',
				500 * 1024 * 1024,
			);
		});

		it('should return shutting_down when SIGTERM is received', async () => {
			process.emit('SIGTERM');

			const result = await controller.isItWorking();

			expect(result).toEqual({
				status: 'shutting_down',
				info: {},
				error: {},
				details: {},
			});
			expect(mockHealth.check).not.toHaveBeenCalled();
		});
	});
});

