import * as fs from 'node:fs';
import * as path from 'node:path';

import { INestApplication } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';
import * as dotenv from 'dotenv';

import {
	GLOBAL_PREFIX,
	GRACEFUL_SHUTDOWN_DELAY,
	IS_COMPACT_LOGS,
	IS_JSON_LIKE_LOGS,
	NODE_ENV,
	PORT,
	SERVER_NAME,
} from '../src/constants/env-variables.constant';
import { EnvConfigModule } from '../src/modules/env-config/env-config.module';
import { EnvConfigService } from '../src/modules/env-config/env-config.service';

describe('EnvConfigModule (e2e)', () => {
	let app: INestApplication;
	let envConfigService: EnvConfigService;
	const testEnvVariables: Record<string, string | number | boolean> = {};

	beforeAll(async () => {
		const envFilePath = path.resolve(process.cwd(), '.env.test');
		const envConfig = dotenv.parse(fs.readFileSync(envFilePath));

		testEnvVariables[NODE_ENV] = String(envConfig[NODE_ENV]);
		testEnvVariables[PORT] = Number(envConfig[PORT]);
		testEnvVariables[GLOBAL_PREFIX] = String(envConfig[GLOBAL_PREFIX]);
		testEnvVariables[SERVER_NAME] = String(envConfig[SERVER_NAME]);
		testEnvVariables[IS_COMPACT_LOGS] = envConfig[IS_COMPACT_LOGS] === 'true';
		testEnvVariables[IS_JSON_LIKE_LOGS] = envConfig[IS_JSON_LIKE_LOGS] === 'true';
		testEnvVariables[GRACEFUL_SHUTDOWN_DELAY] = Number(envConfig[GRACEFUL_SHUTDOWN_DELAY]);

		const moduleFixture: TestingModule = await Test.createTestingModule({
			imports: [EnvConfigModule],
		}).compile();

		app = moduleFixture.createNestApplication();
		envConfigService = moduleFixture.get<EnvConfigService>(EnvConfigService);

		await app.init();
	});

	afterAll(async () => {
		await app.close();
	});

	describe('Module structure', () => {
		it('should initialise and export EnvConfigService', () => {
			expect(envConfigService).toBeDefined();
			expect(envConfigService).toBeInstanceOf(EnvConfigService);
		});
	});

	describe('Configuration loading', () => {
		it('should load string variables correctly', () => {
			expect(envConfigService.get<string>({ key: NODE_ENV })).toBe(
				testEnvVariables[NODE_ENV],
			);
			expect(envConfigService.get<string>({ key: GLOBAL_PREFIX })).toBe(
				testEnvVariables[GLOBAL_PREFIX],
			);
			expect(envConfigService.get<string>({ key: SERVER_NAME })).toBe(
				testEnvVariables[SERVER_NAME],
			);
		});

		it('should load numeric variables correctly with converter', () => {
			expect(envConfigService.get<number>({ key: PORT, converter: Number })).toBe(
				testEnvVariables[PORT],
			);
			expect(
				envConfigService.get<number>({ key: GRACEFUL_SHUTDOWN_DELAY, converter: Number }),
			).toBe(testEnvVariables[GRACEFUL_SHUTDOWN_DELAY]);
		});

		it('should load boolean variables correctly with converter', () => {
			expect(
				envConfigService.get<boolean>({ key: IS_COMPACT_LOGS, converter: Boolean }),
			).toBe(testEnvVariables[IS_COMPACT_LOGS]);
			expect(
				envConfigService.get<boolean>({ key: IS_JSON_LIKE_LOGS, converter: Boolean }),
			).toBe(testEnvVariables[IS_JSON_LIKE_LOGS]);
		});
	});

	describe('Error handling', () => {
		it('should throw for non-existent environment variable', () => {
			expect(() => envConfigService.get<string>({ key: 'NON_EXISTENT_VARIABLE' })).toThrow(
				'Environment variable NON_EXISTENT_VARIABLE is not defined',
			);
		});
	});

	describe('Type conversions', () => {
		it('should return numeric type when Number converter is used', () => {
			const port = envConfigService.get<number>({ key: PORT, converter: Number });
			expect(typeof port).toBe('number');
		});

		it('should provide config to downstream services via DI', async () => {
			const testModuleFixture: TestingModule = await Test.createTestingModule({
				imports: [EnvConfigModule],
				providers: [
					{
						provide: 'PORT_PROVIDER',
						useFactory: (config: EnvConfigService) =>
							config.get<number>({ key: PORT, converter: Number }),
						inject: [EnvConfigService],
					},
				],
			}).compile();

			const portValue = testModuleFixture.get<number>('PORT_PROVIDER');
			expect(portValue).toBe(testEnvVariables[PORT]);
		});
	});
});

