import { INestApplication } from '@nestjs/common';
import {
	HealthIndicatorResult,
	HealthIndicatorService,
	MemoryHealthIndicator,
	TerminusModule,
} from '@nestjs/terminus';
import { Test, TestingModule } from '@nestjs/testing';
import * as request from 'supertest';
import type { App } from 'supertest/types';

import { HealthController } from '../src/modules/health/health.controller';
import { HealthService } from '../src/modules/health/health.service';

describe('HealthModule (e2e)', () => {
	let app: INestApplication;
	let httpServer: App;

	const healthyIndicatorResult: HealthIndicatorResult = {
		app: { status: 'up', message: 'App is running', uptime: 0, timestamp: 0 },
	};

	const mockHealthIndicatorService = {
		check: jest.fn().mockReturnValue({
			up: jest.fn().mockReturnValue(healthyIndicatorResult),
		}),
	};

	const mockMemoryHealthIndicator = {
		checkHeap: jest.fn().mockResolvedValue({ memory_heap: { status: 'up' } }),
	};

	beforeAll(async () => {
		const moduleFixture: TestingModule = await Test.createTestingModule({
			imports: [
				TerminusModule.forRoot({
					gracefulShutdownTimeoutMs: 0,
					errorLogStyle: 'json',
				}),
			],
			controllers: [HealthController],
			providers: [
				HealthService,
				{ provide: HealthIndicatorService, useValue: mockHealthIndicatorService },
				{ provide: MemoryHealthIndicator, useValue: mockMemoryHealthIndicator },
			],
		}).compile();

		app = moduleFixture.createNestApplication();
		httpServer = app.getHttpServer() as App;

		await app.init();
	});

	afterAll(async () => {
		await app.close();
	});

	describe('GET /liveness', () => {
		it('should return 200 with status up', async () => {
			const response = await request(httpServer).get('/liveness').expect(200);

			expect(response.body).toEqual({ status: 'up' });
		});
	});

	describe('GET /readiness', () => {
		it('should return 200 and call health indicators', async () => {
			const response = await request(httpServer).get('/readiness').expect(200);

			expect(response.body).toMatchObject({ status: 'ok' });
			expect(mockHealthIndicatorService.check).toHaveBeenCalledWith('app');
			expect(mockMemoryHealthIndicator.checkHeap).toHaveBeenCalledWith(
				'memory_heap',
				500 * 1024 * 1024,
			);
		});

		it('should return shutting_down after SIGTERM', async () => {
			process.emit('SIGTERM');

			const response = await request(httpServer).get('/readiness').expect(200);

			expect(response.body).toMatchObject({ status: 'shutting_down' });
		});
	});
});

